class Solution:
    def minSumSquareDiff(self, nums1: List[int], nums2: List[int], k1: int, k2: int) -> int:
        n = len(nums1)
        for i in range(n):
            if k1 > 0 and k2 > 0:
                if abs(nums1[i] - nums2[i]) % 2 == 1:
                    if k1 > k2:
                        nums1[i] += 1
                        k1 -= 1
                    else:
                        nums2[i] += 1
                        k2 -= 1
                else:
                    if k1 > k2:
                        nums1[i] += 1
                        k1 -= 1
                    else:
                        nums2[i] += 1
                        k2 -= 1
            elif k1 > 0:
                nums1[i] += 1
                k1 -= 1
            elif k2 > 0:
                nums2[i] += 1
                k2 -= 1
        return sum((nums1[i] - nums2[i]) ** 2 for i in range(n))
